1	export type Item = { kind: "sword" | "amulet" | "staff" | "potion" };
2	
3	export type QuoteStep = { kind: "quote"; items: Item[] };
4	
5	export type Scenario = {
6	  customer: { yearsWithMHPCO: number };
7	  steps: QuoteStep[];
8	};
9	
10	export type ScenarioResult = {
11	  results: unknown[];
12	};
13	
14	const BASE_PREMIUM_BY_ITEM: Record<Item["kind"], number> = {
15	  sword: 100,
16	  amulet: 60,
17	  staff: 80,
18	};
19	
20	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
21	const PROCESSING_FEE = 5;
22	
23	export function processScenario(scenario: Scenario): ScenarioResult {
24	  const results = scenario.steps.map((step) => {
25	    const item = step.items[0];
26	    const basePremium = BASE_PREMIUM_BY_ITEM[item.kind];
27	    const surcharge = basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
28	    const premium = basePremium + surcharge + PROCESSING_FEE;
29	    return { kind: "quote" as const, premium };
30	  });
31	  return { results };
32	}
33

